SELECT ANALYZE_HISTORY_ID, SERVER_ID, ANALYZE_TARGET_DATE, SOURCE_FILE_PATH, LAST_ANALYZE_LOG_ID, ANALYZE_STATUS, TOTAL_COUNT, SUCCESS_COUNT, FAIL_COUNT, ERROR_COUNT, WARNING_COUNT, FAIL_REASON, ANALYZE_START_AT, ANALYZE_END_AT, ANALYZE_DATE, CREATED_AT, UPDATED_AT FROM TB_ANALYZE_HISTORY
ANALYZE_STATUS = 'SUCCESS' AND SERVER_ID = #{serverId}
AND SOURCE_FILE_PATH = #{sourceFilePath}
AND SOURCE_FILE_PATH IS NULL
ORDER BY ANALYZE_START_AT DESC FETCH FIRST 1 ROW ONLY
